import type FluentStream from "./FluentStream.js";

export type PresetFn = (
  stream: FluentStream,
  options?: Record<string, unknown>,
) => void;

const presets: Record<string, PresetFn> = {
  discord(stream) {
    stream
      .inputOptions(
        "-fflags",
        "nobuffer",
        "-flags",
        "low_delay",
        "-probesize",
        "32",
        "-analyzeduration",
        "0",
      )
      .audioCodec("pcm_s16le")
      .audioFrequency(48000)
      .audioChannels(2)
      .format("s16le");
  },

  twitter(stream, opts) {
    const resolution = (opts?.resolution as string) ?? "1280x720";
    stream
      .videoCodec("libx264")
      .audioCodec("aac")
      .audioBitrate("128k")
      .videoBitrate("2500k")
      .outputOptions(
        "-vf",
        `scale=${resolution}`,
        "-preset",
        "medium",
        "-crf",
        "23",
        "-pix_fmt",
        "yuv420p",
        "-movflags",
        "+faststart",
      )
      .format("mp4");
  },

  x(stream, opts) {
    (presets.twitter as PresetFn)(stream, opts);
  },

  vod(stream, opts) {
    const resolution = (opts?.resolution as string) ?? "1920x1080";
    stream
      .videoCodec("libx264")
      .audioCodec("aac")
      .audioBitrate("192k")
      .videoBitrate("4000k")
      .outputOptions(
        "-vf",
        `scale=${resolution}`,
        "-preset",
        "slow",
        "-crf",
        "18",
        "-pix_fmt",
        "yuv420p",
      )
      .format("mp4");
  },

  stream(stream, opts) {
    const isAudioOnly = opts?.audioOnly as boolean | undefined;
    if (isAudioOnly) {
      stream.audioCodec("aac").audioBitrate("128k").outputOptions("-vn", "-f", "mp4");
    } else {
      stream
        .videoCodec("libx264")
        .audioCodec("aac")
        .audioBitrate("128k")
        .videoBitrate("3500k")
        .outputOptions(
          "-preset",
          "veryfast",
          "-crf",
          "23",
          "-pix_fmt",
          "yuv420p",
          "-g",
          "60",
          "-f",
          "flv",
        );
    }
  },

  audio(stream) {
    stream.audioCodec("pcm_s16le").outputOptions("-vn").format("wav");
  },
};

export function getPreset(name: string): PresetFn | undefined {
  return presets[name.toLowerCase()];
}

export function getPresetNames(): string[] {
  return Object.keys(presets);
}
